import React from 'react';
import { Lightbulb, Wrench, Home, Zap, Settings, Thermometer, Construction, PenTool } from 'lucide-react';

const Services = () => {
  const services = [
    { title: "House Wiring", icon: <Home className="text-yellow-500" /> },
    { title: "Fan & Light Fitting", icon: <Lightbulb className="text-yellow-500" /> },
    { title: "Switch Board Repair", icon: <Settings className="text-yellow-500" /> },
    { title: "Inverter & Meter Work", icon: <Zap className="text-yellow-500" /> },
    { title: "Cooler & AC Repair", icon: <Thermometer className="text-yellow-500" /> },
    { title: "Kitchen Appliances", icon: <Wrench className="text-yellow-500" /> },
    { title: "1BHK/2BHK Wiring", icon: <Construction className="text-yellow-500" /> },
    { title: "Industrial Fitting", icon: <PenTool className="text-yellow-500" /> },
  ];

  return (
    <section className="py-20">
      <div className="text-center mb-16">
        <h2 className="text-4xl font-bold mb-4">Our <span className="text-yellow-500">Services</span></h2>
        <div className="w-24 h-1 bg-yellow-500 mx-auto"></div>
        <p className="mt-6 text-gray-400 max-w-2xl mx-auto">
          We provide a wide range of electrical services with high quality standards and safety protocols.
        </p>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        {services.map((service, index) => (
          <div
            key={index}
            className="glass p-6 rounded-2xl hover:bg-white/5 transition-all group border border-white/5"
          >
            <div className="w-12 h-12 rounded-xl bg-yellow-500/10 flex items-center justify-center mb-4 group-hover:bg-yellow-500/20 transition-colors">
              {service.icon}
            </div>
            <h3 className="text-xl font-bold mb-2">{service.title}</h3>
            <p className="text-sm text-gray-400">Professional installation and repair services with guarantee.</p>
          </div>
        ))}
      </div>
    </section>
  );
};

export default Services;
